SELECT tc_id, ATAN(overall_average_tc) AS atan_overall_average_tc
FROM temperature_control_points
WHERE overall_average_tc > 100;

SELECT tc_id, west_upper_tc, west_middle_tc
FROM temperature_control_points
WHERE west_upper_tc IS NOT NULL AND west_middle_tc IS NOT NULL;

SELECT e.equipment_name, c.compliance_status, c.compliance_standard
FROM equipment e
INNER JOIN compliance_records c ON e.equipment_id = c.test_id;

SELECT tp.*, cr.compliance_status
FROM test_protocols tp
INNER JOIN compliance_records cr ON tp.protocol_id = cr.test_id;

SELECT east_upper_tc
FROM temperature_control_points
WHERE east_upper_tc > 80.0;

SELECT tc.test_id, tc.west_upper_tc
FROM temperature_control_points tc
WHERE tc.west_upper_tc > (SELECT AVG(west_upper_tc) FROM temperature_control_points);

SELECT standard_name
FROM compliance_standards
WHERE standard_id IN (
  SELECT DISTINCT compliance_standard
  FROM compliance_records
);

SELECT DISTINCT users.user_name
FROM users
JOIN compliance_records ON users.user_id = compliance_records.test_id;

SELECT fuel_type_name
FROM fuel_types
WHERE fuel_type_name = 'Natural Gas';

SELECT equipment_name
FROM equipment
WHERE ABS(julianday('now') - julianday(calibration_date)) = (
  SELECT MIN(ABS(julianday('now') - julianday(calibration_date)))
  FROM equipment
);
